1	package graph
2	
3	import (
4		"fmt"
5	
6		v1 "k8s.io/api/core/v1"
7		"k8s.io/apimachinery/pkg/types"
8		"sigs.k8s.io/controller-runtime/pkg/client"
9		inference "sigs.k8s.io/gateway-api-inference-extension/api/v1"
10		apiv1 "sigs.k8s.io/gateway-api/apis/v1"
11	
12		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/conditions"
13		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
14	)
15	
16	// A ReferencedInferencePool represents an InferencePool that is referenced by a Route and the
17	// Gateways it belongs to.
18	type ReferencedInferencePool struct {
19		// Source is the original InferencePool that this ReferencedInferencePool is based on.
20		Source *inference.InferencePool
21		// Gateways are the Gateways that this ReferencedInferencePool is attached to.
22		Gateways []*apiv1.Gateway
23		// HTTPRoutes are the HTTPRoutes that reference this InferencePool.
24		HTTPRoutes []*L7Route
25		// Conditions contains the conditions that should be applied to the InferencePool.
26		Conditions []conditions.Condition
27		// Valid indicates whether the InferencePool is valid or not.
28		Valid bool
29	}
30	
31	// EndpointPickerConfig specifies the namespace and reference to the EndpointPicker extension.
32	type EndpointPickerConfig struct {
33		// EndpointPickerRef is the reference to the EndpointPicker.
34		EndpointPickerRef *inference.EndpointPickerRef
35		// NsName is the namespace of the EndpointPicker.
36		NsName string
37	}
38	
39	// buildReferencedInferencePools builds a map of InferencePools that are referenced by HTTPRoutes
40	// per Gateway that we process.
41	func buildReferencedInferencePools(
42		routes map[RouteKey]*L7Route,
43		gws map[types.NamespacedName]*Gateway,
44		inferencePools map[types.NamespacedName]*inference.InferencePool,
45		services map[types.NamespacedName]*v1.Service,
46		listenerSets map[types.NamespacedName]*ListenerSet,
47	) map[types.NamespacedName]*ReferencedInferencePool {
48		referencedInferencePools := make(map[types.NamespacedName]*ReferencedInferencePool, len(inferencePools))
49	
50		for _, gw := range gws {
51			if gw == nil {
52				continue
53			}
54	
55			processInferencePoolsForGateway(routes, gw, referencedInferencePools, inferencePools, listenerSets)
56		}
57	
58		if len(referencedInferencePools) == 0 {
59			return nil
60		}
61	
62		// validate each referenced InferencePool and add conditions.
63		for _, refPool := range referencedInferencePools {
64			if routeCond := validateInferencePoolRoutesAcceptance(refPool.Source, refPool.HTTPRoutes); routeCond != nil {
65				refPool.Conditions = append(refPool.Conditions, *routeCond)
66			}
67	
68			if extensionRefCond := validateInferencePoolExtensionRef(refPool.Source, services); extensionRefCond != nil {
69				refPool.Conditions = append(refPool.Conditions, *extensionRefCond)
70			}
71	
72			refPool.Valid = len(refPool.Conditions) == 0
73		}
74	
75		return referencedInferencePools
76	}
77	
78	// processInferencePoolsForGateway processes all InferencePools that belong to the given gateway.
79	func processInferencePoolsForGateway(
80		routes map[RouteKey]*L7Route,
81		gw *Gateway,
82		referencedInferencePools map[types.NamespacedName]*ReferencedInferencePool,
83		inferencePools map[types.NamespacedName]*inference.InferencePool,
84		listenerSets map[types.NamespacedName]*ListenerSet,
85	) {
86		gwKey := client.ObjectKeyFromObject(gw.Source)
87	
88		for _, route := range routes {
89			if !routeBelongsToGateway(route.ParentRefs, gwKey, listenerSets) {
90				continue
91			}
92	
93			for _, rule := range route.Spec.Rules {
94				for _, ref := range rule.RouteBackendRefs {
95					if !ref.IsInferencePool && (ref.Kind == nil || *ref.Kind != kinds.InferencePool) {
96						continue
97					}
98	
99					namespace := route.Source.GetNamespace()
100					if ref.Namespace != nil {
101						namespace = string(*ref.Namespace)
102					}
103	
104					name := ref.InferencePoolName
105					if name == "" {
106						name = string(ref.Name)
107					}
108	
109					poolName := types.NamespacedName{
110						Name:      name,
111						Namespace: namespace,
112					}
113	
114					if _, referenced := referencedInferencePools[poolName]; !referenced {
115						referencedInferencePools[poolName] = &ReferencedInferencePool{
116							Conditions: make([]conditions.Condition, 0, 2),
117							Gateways:   make([]*apiv1.Gateway, 0),
118							HTTPRoutes: make([]*L7Route, 0),
119						}
120					}
121	
122					if pool, exists := inferencePools[poolName]; exists {
123						referencedInferencePools[poolName].Source = pool
124						referencedInferencePools[poolName].Gateways = append(
125							referencedInferencePools[poolName].Gateways,
126							gw.Source,
127						)
128						referencedInferencePools[poolName].HTTPRoutes = append(
129							referencedInferencePools[poolName].HTTPRoutes,
130							route,
131						)
132					}
133				}
134			}
135		}
136	}
137	
138	// validateInferencePoolExtensionRef validates the ExtensionRef of the InferencePool.
139	func validateInferencePoolExtensionRef(
140		ip *inference.InferencePool,
141		svc map[types.NamespacedName]*v1.Service,
142	) *conditions.Condition {
143		var failingCond conditions.Condition
144		if ip == nil {
145			return nil
146		}
147	
148		// if kind is empty, it defaults to Service
149		kind := string(ip.Spec.EndpointPickerRef.Kind)
150		if kind == "" {
151			kind = kinds.Service
152		}
153	
154		if kind != kinds.Service {
155			failingCond = conditions.NewInferencePoolInvalidExtensionref("Invalid ExtensionRef kind: " + kind)
156			return &failingCond
157		}
158	
159		eppNsName := types.NamespacedName{
160			Name:      string(ip.Spec.EndpointPickerRef.Name),
161			Namespace: ip.GetNamespace(),
162		}
163	
164		if _, ok := svc[eppNsName]; !ok {
165			failingCond = conditions.NewInferencePoolInvalidExtensionref(
166				"The ExtensionRef Service not found: " + eppNsName.String(),
167			)
168			return &failingCond
169		}
170	
171		return nil
172	}
173	
174	// validateInferencePoolRoutesAcceptance checks if the routes that reference the InferencePool
175	// are accepted by the Gateway.
176	func validateInferencePoolRoutesAcceptance(ip *inference.InferencePool, routes []*L7Route) *conditions.Condition {
177		if ip == nil || len(routes) == 0 {
178			return nil
179		}
180	
181		// we do not need to validate that the route belongs to the gateway or not
182		// we only process routes that belong to the gateway in the first place
183		for _, route := range routes {
184			if !route.Valid {
185				cond := conditions.NewInferencePoolInvalidHTTPRouteNotAccepted(
186					fmt.Sprintf("Referenced HTTPRoute %s/%s is not accepted by the Gateway",
187						route.Source.GetNamespace(),
188						route.Source.GetName(),
189					),
190				)
191				return &cond
192			}
193		}
194	
195		return nil
196	}
